input.content:
const PROCESSING_FEE = 5;

interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

export const processScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => {
    if (step.items.length === 0) return { premium: PROCESSING_FEE };
    return { premium: 115 };
  });
  return { results };
};

